  function getLastMondayAt5AM() {
    var now = new Date(), day = now.getDay();
    var d = new Date(now);
    d.setDate(now.getDate() - (day === 0 ? 6 : day - 1));
    d.setHours(5, 0, 0, 0);
    if (d > now) d.setDate(d.getDate() - 7);
    return d;
